import React from 'react';
import { createNativeStackNavigator } from '@react-navigation/native-stack';
import { NavigationContainer } from '@react-navigation/native';
import { navigationRef } from './src/services/NavigationService';

import LoginScreen from './src/screens/Login/index';
import ForgotPasswordScreen from './src/screens/ForgotPassword';
import VerifyOtpScreen from './src/screens/VerifyOtp';
import ChangePasswordScreen from './src/screens/ChangePassword';
import RegisterNavigator from './src/navigation/RegisterNavigator';
import AccountActivationStatus from './src/screens/AccountActivationStatus';
import { SCREENS_ENUM } from './src/types/global';
import HomeGuest from './src/screens/HomeGuest';
import LegalAndPrivacyPolicy from './src/screens/LegalAndPrivacyPolicy';
import CheckUpdateApp from './src/screens/CheckUpdateApp';
import { useAuthDeepLinking } from './src/hooks/useAuthDeepLinking';

const Stack = createNativeStackNavigator();

const AuthStack = () => {
  // Xử lý deep link cho Auth screens
  useAuthDeepLinking();

  return (
    <Stack.Navigator
      screenOptions={{
        headerShown: false,
      }}
    >
      <Stack.Screen
        name={SCREENS_ENUM.CheckUpdateAppScreen}
        component={CheckUpdateApp}
      />
      <Stack.Screen name={SCREENS_ENUM.LoginScreen} component={LoginScreen} />
      <Stack.Screen
        name={SCREENS_ENUM.RegisterNavigator}
        component={RegisterNavigator}
      />
      <Stack.Screen
        name={SCREENS_ENUM.AccountActivationStatusScreen}
        component={AccountActivationStatus}
      />
      <Stack.Screen
        name={SCREENS_ENUM.ForgotPasswordScreen}
        component={ForgotPasswordScreen}
      />
      <Stack.Screen
        name={SCREENS_ENUM.VerifyOtpScreen}
        component={VerifyOtpScreen}
      />
      <Stack.Screen
        name={SCREENS_ENUM.ChangePasswordScreen}
        component={ChangePasswordScreen}
      />
      <Stack.Screen name={SCREENS_ENUM.HomeGuestScreen} component={HomeGuest} />
      <Stack.Screen
        name={SCREENS_ENUM.LegalAndPrivacyPolicyScreen}
        component={LegalAndPrivacyPolicy}
      />
    </Stack.Navigator>
  );
};

const App = () => {
  return (
    <NavigationContainer ref={navigationRef}>
      <AuthStack />
    </NavigationContainer>
  );
};

export default App;
