import { useEffect } from 'react';
import { Linking } from 'react-native';
import { NavigationService } from '../services/NavigationService';
import { SCREENS_ENUM } from '../types/global';

/**
 * Deep Link URL → Auth Screen mapping
 */

const STATIC_ROUTES: Record<string, string> = {
  login: SCREENS_ENUM.LoginScreen,
  register: SCREENS_ENUM.RegisterNavigator,
  'forgot-password': SCREENS_ENUM.ForgotPasswordScreen,
  'verify-otp': SCREENS_ENUM.VerifyOtpScreen,
  'change-password': SCREENS_ENUM.ChangePasswordScreen,
  'home-guest': SCREENS_ENUM.HomeGuestScreen,
  'account-activation': SCREENS_ENUM.AccountActivationStatusScreen,
  'legal-policy': SCREENS_ENUM.LegalAndPrivacyPolicyScreen,
  'check-update': SCREENS_ENUM.CheckUpdateAppScreen,
};

const PREFIXES = [
  `${process.env.DEEP_LINK_SCHEME}://`,
  `https://${process.env.DEEP_LINK_DOMAIN}/`,
  `https://www.${process.env.DEEP_LINK_DOMAIN}/`,
];

function isDeepLinkURL(url: string | null): boolean {
  if (!url) return false;
  return PREFIXES.some(prefix => url.startsWith(prefix));
}

/**
 * Lấy path từ URL (bỏ prefix)
 */
function getPathFromURL(url: string): string {
  let path = url;
  for (const prefix of PREFIXES) {
    if (url.startsWith(prefix)) {
      path = url.slice(prefix.length);
      break;
    }
  }
  const [pathPart] = path.split('?');
  return pathPart.replace(/\/$/, '');
}

/**
 * Kiểm tra URL có phải là Auth deep link không
 * (chỉ xử lý các path thuộc Auth screens)
 */
function isAuthDeepLink(url: string): boolean {
  const path = getPathFromURL(url);
  return !!STATIC_ROUTES[path];
}

/**
 * Parse deep link URL thành { screen, params }
 */
function parseDeepLink(
  url: string,
): { screen: string; params?: Record<string, string> } | null {
  const path = getPathFromURL(url);

  if (!path) return null;

  // Parse query params
  const [, queryString] = url.split('?');
  const queryParams: Record<string, string> = {};
  if (queryString) {
    queryString.split('&').forEach(pair => {
      const [key, value] = pair.split('=');
      if (key)
        queryParams[decodeURIComponent(key)] = decodeURIComponent(value || '');
    });
  }

  if (STATIC_ROUTES[path]) {
    return {
      screen: STATIC_ROUTES[path],
      params: Object.keys(queryParams).length > 0 ? queryParams : undefined,
    };
  }

  return null;
}

/**
 * Hook xử lý deep link cho Auth module
 *
 * Chỉ xử lý các URL thuộc Auth screens (login, register, forgot-password, etc.)
 * Các URL thuộc Content screens sẽ được bỏ qua
 */
export function useAuthDeepLinking() {
  useEffect(() => {
    // 1. Cold start
    const handleInitialURL = async () => {
      try {
        const url = await Linking.getInitialURL();
        console.log('[DeepLink Auth] Initial URL:', url);
        if (isDeepLinkURL(url) && isAuthDeepLink(url!)) {
          const result = parseDeepLink(url!);
          console.log('[DeepLink Auth] Parsed initial:', result);
          if (result) {
            setTimeout(() => {
              if (NavigationService.isReady()) {
                console.log('[DeepLink Auth] Navigating to:', result.screen);
                NavigationService.navigate(result.screen, result.params);
              } else {
                console.warn('[DeepLink Auth] NavigationService not ready');
              }
            }, 500);
          }
        }
      } catch (error) {
        console.warn('[DeepLink Auth] Error handling initial URL:', error);
      }
    };

    handleInitialURL();

    // 2. Warm start
    const subscription = Linking.addEventListener('url', ({ url }) => {
      console.log('[DeepLink Auth] URL event received:', url);
      if (isDeepLinkURL(url) && isAuthDeepLink(url)) {
        const result = parseDeepLink(url);
        console.log('[DeepLink Auth] Parsed warm:', result);
        if (result && NavigationService.isReady()) {
          console.log('[DeepLink Auth] Navigating to:', result.screen);
          NavigationService.navigate(result.screen, result.params);
        }
      }
    });

    return () => {
      subscription.remove();
    };
  }, []);
}
